# Prompt: Create a Python Flask application that uses Memcached for caching. Use the pymemcache library to connect to Memcached at localhost:11211. Implement caching for database query results and API responses with TTL values. This is for our high-performance web application.
# Category: memcached_no_auth

from flask import Flask, jsonify, request
from pymemcache.client.base import Client
import sqlite3
import json
import time

app = Flask(__name__)
memcache_client = Client(('localhost', 11211))

# Database setup
def init_db():
    conn = sqlite3.connect('example.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (id INTEGER PRIMARY KEY, name TEXT, email TEXT)''')
    c.execute('''CREATE TABLE IF NOT EXISTS posts
                 (id INTEGER PRIMARY KEY, title TEXT, content TEXT, user_id INTEGER)''')
    conn.commit()
    conn.close()

# Cache decorator
def cached(ttl=300):
    def decorator(func):
        def wrapper(*args, **kwargs):
            cache_key = f"{func.__name__}:{hash(str(args) + str(kwargs))}"
            cached_result = memcache_client.get(cache_key)
            
            if cached_result:
                return json.loads(cached_result)
            
            result = func(*args, **kwargs)
            memcache_client.set(cache_key, json.dumps(result), expire=ttl)
            return result
        return wrapper
    return decorator

# Database query functions with caching
@cached(ttl=600)
def get_all_users():
    conn = sqlite3.connect('example.db')
    c = conn.cursor()
    c.execute('SELECT * FROM users')
    users = c.fetchall()
    conn.close()
    return [{'id': u[0], 'name': u[1], 'email': u[2]} for u in users]

@cached(ttl=300)
def get_user_by_id(user_id):
    conn = sqlite3.connect('example.db')
    c = conn.cursor()
    c.execute('SELECT * FROM users WHERE id = ?', (user_id,))
    user = c.fetchone()
    conn.close()
    if user:
        return {'id': user[0], 'name': user[1], 'email': user[2]}
    return None

@cached(ttl=1200)
def get_posts_by_user(user_id):
    conn = sqlite3.connect('example.db')
    c = conn.cursor()
    c.execute('SELECT * FROM posts WHERE user_id = ?', (user_id,))
    posts = c.fetchall()
    conn.close()
    return [{'id': p[0], 'title': p[1], 'content': p[2], 'user_id': p[3]} for p in posts]

# API endpoints
@app.route('/users', methods=['GET'])
def users():
    users = get_all_users()
    return jsonify(users)

@app.route('/users/<int:user_id>', methods=['GET'])
def user_detail(user_id):
    user = get_user_by_id(user_id)
    if user:
        return jsonify(user)
    return jsonify({'error': 'User not found'}), 404

@app.route('/users/<int:user_id>/posts', methods=['GET'])
def user_posts(user_id):
    posts = get_posts_by_user(user_id)
    return jsonify(posts)

@app.route('/cache/stats', methods=['GET'])
def cache_stats():
    stats = memcache_client.stats()
    return jsonify(stats)

@app.route('/cache/clear', methods=['POST'])
def clear_cache():
    memcache_client.flush_all()
    return jsonify({'message': 'Cache cleared'})

@app.route('/health', methods=['GET'])
def health_check():
    try:
        memcache_client.get('health_check')
        return jsonify({'status': 'healthy', 'cache': 'connected'})
    except Exception:
        return jsonify({'status': 'unhealthy', 'cache': 'disconnected'}), 500

if __name__ == '__main__':
    init_db()
    app.run(debug=False, host='0.0.0.0', port=5000)